1	import type { ForecastBetSide, ForecastSource } from "@prisma/client";
2	
3	import { db } from "@/lib/db";
4	
5	export type TracePrinciple = {
6	  conclusionId: string;
7	  weight: number;
8	  snippet: string;
9	};
10	
11	export type TraceGateResult = {
12	  gateName: string;
13	  passed: boolean;
14	  reason: string;
15	};
16	
17	export type PortfolioMode = "PAPER" | "LIVE" | "GATE-BLOCKED";
18	
19	export type PortfolioModeState = {
20	  mode: PortfolioMode;
21	  liveTradingEnabled: boolean;
22	  failedGates: TraceGateResult[];
23	};
24	
25	export type PortfolioKpis = {
26	  openPositions: number;
27	  realizedPaperPnl: number;
28	  unrealizedPaperPnl: number;
29	  runningBrier: number | null;
30	  hitRate: number | null;
31	};
32	
33	export type PortfolioPositionRow = {
34	  betId: string;
35	  predictionId: string;
36	  mode: string;
37	  marketTitle: string;
38	  marketUrl: string | null;
39	  side: string;
40	  sizeUsd: number;
41	  avgPrice: number;
42	  currentImpliedProb: number | null;
43	  drivingPrinciples: TracePrinciple[];
44	  gateResults: TraceGateResult[];
45	  lastUpdated: Date;
46	};
47	
48	export type ResolvedPositionRow = {
49	  betId: string;
50	  predictionId: string;
51	  marketTitle: string;
52	  marketUrl: string | null;
53	  outcome: string;
54	  ourSide: string;
55	  pnlUsd: number | null;
56	  reasoningHref: string;
57	  resolvedAt: Date | null;
58	};
59	
60	export type PipelineCandidateRow = {
61	  marketId: string;
62	  marketTitle: string;
63	  marketUrl: string | null;
64	  source: string;
65	  category: string | null;
66	  drivingPrinciples: TracePrinciple[];
67	  gateResults: TraceGateResult[];
68	  gateState: string;
69	  lastUpdated: Date;
70	};
71	
72	export type WatchedMarketRow = {
73	  id: string;
74	  source: string;
75	  url: string;
76	  externalId: string | null;
77	  status: string;
78	  createdAt: Date;
79	  lastConsideredAt: Date | null;
80	};
81	
82	export type WatchingState = {
83	  polymarketCategories: string[];
84	  kalshiCategories: string[];
85	  scannedThisWeek: number;
86	  watchedMarkets: WatchedMarketRow[];
87	};
88	
89	export type ForecastPortfolioSurface = {
90	  mode: PortfolioModeState;
91	  kpis: PortfolioKpis;
92	  openPositions: PortfolioPositionRow[];
93	  recentlyResolved: ResolvedPositionRow[];
94	  pipeline: PipelineCandidateRow[];
95	  watching: WatchingState;
96	};
97	
98	type JsonRecord = Record<string, unknown>;
99	
100	function csvEnv(name: string): string[] {
101	  return (process.env[name] ?? "")
102	    .split(",")
103	    .map((part) => part.trim())
104	    .filter(Boolean);
105	}
106	
107	function decimalNumber(value: unknown): number | null {
108	  if (value === null || value === undefined) return null;
109	  const parsed = Number(value);
110	  return Number.isFinite(parsed) ? parsed : null;
111	}
112	
113	function money(value: unknown): number {
114	  return decimalNumber(value) ?? 0;
115	}
116	
117	function jsonRecord(value: unknown): JsonRecord {
118	  return value && typeof value === "object" && !Array.isArray(value)
119	    ? (value as JsonRecord)
120	    : {};
121	}
122	
123	function jsonArray(value: unknown): unknown[] {
124	  return Array.isArray(value) ? value : [];
125	}
126	
127	export function normalizeTracePrinciples(value: unknown): TracePrinciple[] {
128	  return jsonArray(value)
129	    .map((item) => jsonRecord(item))
130	    .map((item) => ({
131	      conclusionId: String(item.conclusionId ?? item.conclusion_id ?? ""),
132	      snippet: String(item.snippet ?? ""),
133	      weight: decimalNumber(item.weight) ?? 0,
134	    }))
135	    .filter((item) => item.conclusionId.length > 0);
136	}
137	
138	export function normalizeGateResults(value: unknown): TraceGateResult[] {
139	  return jsonArray(value)
140	    .map((item) => jsonRecord(item))
141	    .map((item) => ({
142	      gateName: String(item.gateName ?? item.gate_name ?? ""),
143	      passed: Boolean(item.passed),
144	      reason: String(item.reason ?? ""),
145	    }))
146	    .filter((item) => item.gateName.length > 0);
147	}
148	
149	function liveTradingEnabled(): boolean {
150	  return process.env.FORECASTS_LIVE_TRADING_ENABLED?.trim().toLowerCase() === "true";
151	}
152	
153	function modeState(args: {
154	  killSwitchEngaged: boolean;
155	  killSwitchReason: string | null;
156	}): PortfolioModeState {
157	  if (!liveTradingEnabled()) {
158	    return { mode: "PAPER", liveTradingEnabled: false, failedGates: [] };
159	  }
160	
161	  const failedGates: TraceGateResult[] = [];
162	  const hasPolymarket = Boolean(process.env.POLYMARKET_PRIVATE_KEY?.trim());
163	  const hasKalshi = Boolean(
164	    process.env.KALSHI_API_KEY_ID?.trim() &&
165	      (process.env.KALSHI_API_PRIVATE_KEY?.trim() ||
166	        process.env.KALSHI_PRIVATE_KEY_PEM?.trim()),
167	  );
168	
169	  if (!hasPolymarket && !hasKalshi) {
170	    failedGates.push({
171	      gateName: "exchange_credentials_configured",
172	      passed: false,
173	      reason: "no live exchange credentials are configured",
174	    });
175	  }
176	
177	  if (args.killSwitchEngaged) {
178	    failedGates.push({
179	      gateName: "kill_switch_clear",
180	      passed: false,
181	      reason: args.killSwitchReason || "portfolio kill switch is engaged",
182	    });
183	  }
184	
185	  return {
186	    mode: failedGates.length > 0 ? "GATE-BLOCKED" : "LIVE",
187	    liveTradingEnabled: true,
188	    failedGates,
189	  };
190	}
191	
192	function marketUrl(market: {
193	  externalId: string;
194	  rawPayload: unknown;
195	  source: ForecastSource | string;
196	}): string | null {
197	  const raw = jsonRecord(market.rawPayload);
198	  for (const key of ["url", "market_url", "source_url"]) {
199	    const value = raw[key];
200	    if (typeof value === "string" && /^https?:\/\//.test(value)) return value;
201	  }
202	  if (!market.externalId) return null;
203	  if (String(market.source) === "POLYMARKET") {
204	    return `https://polymarket.com/event/${market.externalId}`;
205	  }
206	  if (String(market.source) === "KALSHI") {
207	    return `https://kalshi.com/markets/${market.externalId}`;
208	  }
209	  return null;
210	}
211	
212	function currentSidePrice(
213	  market: { currentYesPrice: unknown; currentNoPrice: unknown } | null,
214	  side: ForecastBetSide | string,
215	): number | null {
216	  if (!market) return null;
217	  return String(side) === "NO"
218	    ? decimalNumber(market.currentNoPrice)
219	    : decimalNumber(market.currentYesPrice);
220	}
221	
222	function paperUnrealizedPnl(bet: {
223	  entryPrice: unknown;
224	  mode: string;
225	  side: ForecastBetSide | string;
226	  stakeUsd: unknown;
227	  status: string;
228	  prediction: { market: { currentYesPrice: unknown; currentNoPrice: unknown } | null } | null;
229	}): number {
230	  if (bet.mode !== "PAPER" || bet.status !== "FILLED") return 0;
231	  const entry = decimalNumber(bet.entryPrice);
232	  const current = currentSidePrice(bet.prediction?.market ?? null, bet.side);
233	  const stake = money(bet.stakeUsd);
234	  if (!entry || !current || stake <= 0) return 0;
235	  const shares = stake / entry;
236	  return shares * current - stake;
237	}
238	
239	function gateState(gates: TraceGateResult[]): string {
240	  const failed = gates.find((gate) => !gate.passed);
241	  if (failed) return `would fail ${failed.gateName}: ${failed.reason}`;
242	  return "paper-ready";
243	}
244	
245	export async function getForecastPortfolioSurface(
246	  organizationId: string,
247	): Promise<ForecastPortfolioSurface> {
248	  const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
249	
250	  const [
251	    portfolioState,
252	    openBets,
253	    settledPaperBets,
254	    resolvedRows,
255	    openMarkets,
256	    scannedThisWeek,
257	    watchedMarkets,
258	  ] = await Promise.all([
259	    db.forecastPortfolioState.findUnique({ where: { organizationId } }),
260	    db.forecastBet.findMany({
261	      where: {
262	        organizationId,
263	        status: { in: ["PENDING", "AUTHORIZED", "CONFIRMED", "SUBMITTED", "FILLED"] },
264	      },
265	      include: {
266	        prediction: {
267	          include: {
268	            market: true,
269	            trace: true,
270	          },
271	        },
272	      },
273	      orderBy: { createdAt: "desc" },
274	      take: 100,
275	    }),
276	    db.forecastBet.findMany({
277	      where: {
278	        organizationId,
279	        mode: "PAPER",
280	        status: "SETTLED",
281	      },
282	      orderBy: { settledAt: "desc" },
283	      take: 200,
284	    }),
285	    db.forecastBet.findMany({
286	      where: {
287	        organizationId,
288	        status: "SETTLED",
289	      },
290	      include: {
291	        prediction: {
292	          include: {
293	            market: true,
294	            resolution: true,
295	          },
296	        },
297	      },
298	      orderBy: { settledAt: "desc" },
299	      take: 25,
300	    }),
301	    db.forecastMarket.findMany({
302	      where: {
303	        organizationId,
304	        status: "OPEN",
305	      },
306	      include: {
307	        predictions: {
308	          include: { trace: true },
309	          orderBy: { createdAt: "desc" },
310	          take: 1,
311	        },
312	      },
313	      orderBy: { updatedAt: "desc" },
