                    Why:
                  </span>{" "}
                  {algorithmReason}
                </p>
              ) : null}
              <div style={{ marginTop: "0.8rem" }}>
                {liveTradingEnabled ? (
                  <button
                    className="btn"
                    disabled={busyId === row.prediction.id}
                    onClick={async () => {
